/**
 * Get translation for a key in the current language
 */
function getTranslation(key, lang = null) {
    const currentLang = 'en';
    const translations = window.HELP_CENTER_TRANSLATIONS[currentLang] || window.HELP_CENTER_TRANSLATIONS.en;
    return translations[key] || key;
}

/**
 * Translate all UI elements
 */
function translateUI(lang = null) {
    const currentLang = 'en';
    const t = window.HELP_CENTER_TRANSLATIONS[currentLang] || window.HELP_CENTER_TRANSLATIONS.en;
    
    // Always replace title and subtitle with current language only (no duplication)
    const titleEl = document.querySelector('.help-center-title');
    if (titleEl) {
        const icon = titleEl.querySelector('i');
        titleEl.innerHTML = (icon ? icon.outerHTML + ' ' : '') + t.title;
    }
    const subtitleEl = document.querySelector('.help-center-subtitle');
    if (subtitleEl) {
        subtitleEl.textContent = t.subtitle;
    }
    
    // Translate search placeholder (now handled by data-translate-placeholder)
    const searchInput = document.getElementById('helpSearchInput');
    if (searchInput && !searchInput.hasAttribute('data-translate-placeholder')) {
        searchInput.placeholder = t.searchPlaceholder;
    }
    
    // Translate breadcrumbs
    const breadcrumbHome = document.querySelector('.breadcrumb-link[data-action="home"]');
    if (breadcrumbHome) {
        const icon = breadcrumbHome.querySelector('i');
        const homeText = breadcrumbHome.querySelector('.breadcrumb-home-text');
        if (homeText) {
            homeText.textContent = t.home;
        } else {
            breadcrumbHome.innerHTML = (icon ? icon.outerHTML + ' ' : '') + t.home;
        }
    }
    
    const breadcrumbCurrent = document.querySelector('.breadcrumb-current');
    if (breadcrumbCurrent && breadcrumbCurrent.hasAttribute('data-translate')) {
        const translateKey = breadcrumbCurrent.getAttribute('data-translate');
        if (t[translateKey]) {
            breadcrumbCurrent.textContent = t[translateKey];
        }
    } else if (breadcrumbCurrent) {
        const text = breadcrumbCurrent.textContent.trim();
        if (text === 'All Tutorials' || text === 'All Categories') {
            breadcrumbCurrent.textContent = t.allCategories;
        }
    }
    
    // Translate sidebar (now handled by data-translate attributes, but keep for backward compatibility)
    const sidebarHeader = document.querySelector('.sidebar-header h3');
    if (sidebarHeader && !sidebarHeader.hasAttribute('data-translate')) {
        sidebarHeader.textContent = t.categories;
    }
    
    const progressHeader = document.querySelector('#progressSummary h4');
    if (progressHeader && !progressHeader.hasAttribute('data-translate')) {
        progressHeader.textContent = t.yourProgress;
    }
    
    const completedLabels = document.querySelectorAll('.stat-item .stat-label');
    completedLabels.forEach((label, index) => {
        if (!label.hasAttribute('data-translate')) {
            if (label.textContent.includes('Completed')) {
                label.textContent = t.completed;
            } else if (label.textContent.includes('Progress') && index === 1) {
                label.textContent = t.inProgress;
            }
        }
    });
    
    // Translate tutorial list header
    const tutorialListTitle = document.getElementById('tutorialListTitle');
    if (tutorialListTitle) tutorialListTitle.textContent = t.tutorials;
    
    // Translate view toggle buttons
    const viewToggles = document.querySelectorAll('.view-toggle');
    viewToggles.forEach(btn => {
        const viewType = btn.dataset.view;
        if (viewType === 'grid') {
            btn.title = t.gridView;
        } else if (viewType === 'list') {
            btn.title = t.listView;
        }
    });
    
    // Translate search results header
    const searchResultsHeader = document.querySelector('.search-results-header h2');
    if (searchResultsHeader) searchResultsHeader.textContent = t.searchResults;
    
    // Translate empty state
    const emptyStateTitle = document.querySelector('#emptyState h3');
    if (emptyStateTitle) emptyStateTitle.textContent = t.noTutorialsFoundTitle;
    
    const emptyStateText = document.querySelector('#emptyState p');
    if (emptyStateText) emptyStateText.textContent = t.noTutorialsFoundText;
    
    // Translate loading placeholder (always set so it updates when switching language)
    const loadingPlaceholders = document.querySelectorAll('.loading-placeholder');
    loadingPlaceholders.forEach(placeholder => {
        placeholder.innerHTML = '<i class="fas fa-spinner fa-spin"></i> ' + t.loadingCategories;
    });
    
    // Translate modal title (always set so it updates when switching language)
    const modalTitle = document.getElementById('tutorialModalTitle');
    if (modalTitle) {
        modalTitle.textContent = t.tutorial;
    }
    
    // Translate search results count
    const searchResultsCount = document.getElementById('searchResultsCount');
    if (searchResultsCount) {
        const text = searchResultsCount.textContent.trim();
        if (text.includes('results') || text.match(/^\d+\s*results?$/i)) {
            const count = text.match(/\d+/)?.[0] || '0';
            searchResultsCount.textContent = `${count} ${t.results}`;
        }
    }
    
    // Translate language switcher options (always set by value so switching language updates both labels)
    const langSwitcher = document.getElementById('helpLanguageSwitcher');
    if (langSwitcher) {
        const options = langSwitcher.querySelectorAll('option');
        options.forEach(option => {
            if (option.value === 'en') {
                option.textContent = t.languageEnglish;
            } else if (option.value === 'bn') {
                option.remove();
            }
        });
    }
    
    // Translate page title when on Help Center page (so it updates when switching language in either direction)
    if (document.getElementById('helpLanguageSwitcher')) {
        document.title = t.title;
    }
    
    // Translate language label
    const languageLabelText = document.querySelector('.language-label-text');
    if (languageLabelText) {
        languageLabelText.textContent = t.languageLabel;
    }
    
    // Translate all elements with data-translate attribute (title/subtitle already set above)
    document.querySelectorAll('[data-translate]').forEach(el => {
        const key = el.getAttribute('data-translate');
        if (!t[key]) return;
        if (key === 'title' || key === 'subtitle') return;
        if (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') {
            el.placeholder = t[key];
        } else {
            const icon = el.querySelector('i');
            if (icon && el.classList.contains('help-center-title')) {
                el.innerHTML = icon.outerHTML + ' ' + t[key];
            } else {
                el.textContent = t[key];
            }
        }
    });
    
    // Translate elements with data-translate-placeholder attribute
    document.querySelectorAll('[data-translate-placeholder]').forEach(el => {
        const key = el.getAttribute('data-translate-placeholder');
        if (t[key]) {
            el.placeholder = t[key];
        }
    });
    
    // Translate all elements with data-translate-title attribute
    document.querySelectorAll('[data-translate-title]').forEach(el => {
        const key = el.getAttribute('data-translate-title');
        if (t[key]) {
            el.title = t[key];
        }
    });
    
    // Translate all elements with data-translate-aria-label attribute
    document.querySelectorAll('[data-translate-aria-label]').forEach(el => {
        const key = el.getAttribute('data-translate-aria-label');
        if (t[key]) {
            el.setAttribute('aria-label', t[key]);
        }
    });
    
    // Translate back buttons
    const backButtons = document.querySelectorAll('.help-back-button span');
    backButtons.forEach(span => {
        const action = span.closest('.help-back-button')?.getAttribute('data-action');
        if (action === 'backToCategories' && t.backToCategories) {
            span.textContent = t.backToCategories;
        } else if (action === 'backFromDetail' && t.backToTutorials) {
            span.textContent = t.backToTutorials;
        } else if (t.back) {
            span.textContent = t.back;
        }
    });
    
    // Translate search results count
    const resultsCountNumber = document.querySelector('.results-count-number');
    if (resultsCountNumber) {
        const count = resultsCountNumber.textContent.trim();
        const parent = resultsCountNumber.parentElement;
        if (parent && parent.id === 'searchResultsCount') {
            parent.innerHTML = `<span class="results-count-number">${count}</span> <span data-translate="results">${t.results}</span>`;
        }
    }
    
    // Only Help & Learning Center content is translated (main app navbar is not).
}

// Initialize translation system
window.HelpCenterTranslations = {
    currentLanguage: 'en',
    setLanguage: function(lang) {
        this.currentLanguage = 'en';
        translateUI('en');
    },
    get: getTranslation
};
